/**
 * ResizeHandle — draggable divider for resizable panels.
 * Generated by qwen3-coder:30b, reviewed and refined by Jarvis.
 */

import React, { useState, useCallback, useEffect, useRef } from 'react';

interface ResizeHandleProps {
  direction: 'vertical' | 'horizontal';
  onResize: (delta: number) => void;
  style?: React.CSSProperties;
}

export function ResizeHandle({ direction, onResize, style }: ResizeHandleProps) {
  const [isHovered, setIsHovered] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const lastPosRef = useRef(0);

  const handleMouseDown = useCallback((e: React.MouseEvent) => {
    setIsDragging(true);
    lastPosRef.current = direction === 'vertical' ? e.clientX : e.clientY;
    e.preventDefault();
  }, [direction]);

  useEffect(() => {
    if (!isDragging) return;

    const handleMouseMove = (e: MouseEvent) => {
      const currentPos = direction === 'vertical' ? e.clientX : e.clientY;
      const delta = currentPos - lastPosRef.current;
      lastPosRef.current = currentPos;
      if (delta !== 0) {
        onResize(delta);
      }
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, direction, onResize]);

  const isVertical = direction === 'vertical';

  return (
    <div
      style={{
        width: isVertical ? '4px' : '100%',
        height: isVertical ? '100%' : '4px',
        cursor: isVertical ? 'col-resize' : 'row-resize',
        backgroundColor: isDragging ? '#666' : isHovered ? '#555' : '#333',
        userSelect: 'none',
        flexShrink: 0,
        transition: isDragging ? 'none' : 'background-color 0.15s',
        ...style,
      }}
      onMouseDown={handleMouseDown}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    />
  );
}

export default ResizeHandle;
